import { readFileSync } from 'node:fs';
const web=readFileSync('packages/agent-core/src/tools/builtin/web/web-search.ts','utf8');
const local=readFileSync('packages/agent-core/src/tools/providers/local-web-search.ts','utf8');
const c7=readFileSync('packages/agent-core/src/tools/providers/context7.ts','utf8');
const fetchUrl=readFileSync('packages/agent-core/src/tools/builtin/web/fetch-url.ts','utf8');
const fails=[];
if (!web.includes('limit: args.limit ?? 3')) fails.push('web3');
if (!local.includes('INCLUDE_CONTENT_MAX_CHARS = 8_000')) fails.push('include8k');
if (!c7.includes('CONTEXT7_RESOLVE_MAX_MATCHES = 8')) fails.push('c7-8');
if (!c7.includes('CONTEXT7_DOCS_TEXT_MAX_CHARS = 12_000')) fails.push('c7-12k');
if (!fetchUrl.includes('FETCH_URL_CONTENT_MAX_CHARS = 16_000')) fails.push('fetch16k');
if (fails.length){console.error(fails.join(','));process.exit(1);} console.log('web-research-source-ok');
